  ? (buttonId ? 'button' : (text ? 'text' : 'button'))
  : (rawSourceType || 'text');
const resolvedStoreId = state.store_id || start.store_id || null;
const normalizeDigits = (value) => String(value || '').replace(/\D+/g, '');
const hasStateRow = normalizeDigits(state.owner_whatsapp_number) === normalizeDigits(start.chat_id)
  || !!state.store_name
  || !!state.upi_id
  || !!state.delivery_area
  || !!state.operating_hours
  || state.onboarding_step !== undefined
  || !!resolvedStoreId;
const step = hasStateRow ? Number(state.onboarding_step || 0) : 0;
const complete = step >= 6 && !!state.store_name && !!state.upi_id && !!state.delivery_area && !!state.operating_hours;
const bootstrapChoice = buttonId.startsWith('owner_bootstrap_')
  ? buttonId.replace('owner_bootstrap_', '')
  : (/^(add items manually|manual|add items)$/i.test(text) ? 'manual'
    : /^(upload stock sheet|upload inventory|import inventory|import|upload sheet)$/i.test(text) ? 'import'
    : /^(skip|skip for now|later)$/i.test(text) ? 'skip'
    : '');

const hasLanguagePref = state.has_language_pref === true || state.has_language_pref === 't' || state.has_language_pref === 'true' || state.has_language_pref === 1 || state.has_language_pref === '1';

let route = 'already_done';
if (!['text', 'button'].includes(sourceType)) {
  route = 'unsupported_media';
} else if (buttonId.startsWith('set_lang__') && (!hasStateRow || step === 0)) {
  // Language button reply before store is set up → save language then prompt for store name
  route = 'save_language';
} else if (!hasStateRow || step === 0) {
  // New owner — check if language already set
  if (!hasLanguagePref) {
    route = 'send_language_list';
  } else {
    route = (!text || /^(setup|onboard|register|start|start setup)$/i.test(msg)) ? 'init_prompt' : 'save_name';
  }
} else if (complete && bootstrapChoice) {
  route = 'save_bootstrap';
} else if (complete) {
  route = 'already_done';
} else if (step === 1) {
  route = (!text || /^(setup|onboard|register|start|start setup)$/i.test(msg)) ? 'prompt_name' : 'save_name';
} else if (step === 2) {
  route = !text ? 'prompt_upi' : 'save_upi';
} else if (step === 3) {
  route = !text ? 'prompt_area' : 'save_area';
} else if (step === 4) {
  route = !text ? 'prompt_hours' : 'save_hours';
} else if (step === 5) {
  route = bootstrapChoice ? 'save_bootstrap' : 'prompt_bootstrap';
} else {
  route = 'already_done';
}

const langCode = buttonId.startsWith('set_lang__') ? buttonId.replace('set_lang__', '') : (state.user_language || start.user_language || 'en');

return [{ json: {
  ...start,
  ...state,
  store_id: resolvedStoreId,
  route,
  bootstrap_choice: bootstrapChoice,
